def binary_search(list1, item):

    start = 0
    end = len(list1) - 1

    while start <= end:

        middle = (start + end) // 2

        if list1[middle] == item:
            return middle

        elif item < list1[middle]:
            end = middle - 1

        else:
            start = middle + 1

    return -1


