def bsearch(arr, low, high, x):

    if low > high:
        return -1

    mid = (low + high) // 2

    if arr[mid] == x:
        return mid

    elif x < arr[mid]:
        return bsearch(arr, low, mid - 1, x)

    else:
        return bsearch(arr, mid + 1, high, x)


