n = int(input("Enter number of elements: "))

a = []

for i in range(n):
    val = int(input("Enter element: "))
    a.append(val)

key = int(input("Enter element to search: "))

l = 0
h = n - 1

while l <= h:

    m = (l + h) // 2

    if a[m] == key:
        print("Found")
        break

    if key > a[m]:
        l = m + 1
    else:
        h = m - 1

if l > h:
    print("Not Found")

code_b:
def bsearch(arr, low, high, x):

    if low > high:
        return -1

    mid = (low + high) // 2

    if arr[mid] == x:
        return mid

    elif x < arr[mid]:
        return bsearch(arr, low, mid - 1, x)

    else:
        return bsearch(arr, mid + 1, high, x)


arr = [1, 3, 5, 7, 9, 11]

x = 7

ans = bsearch(arr, 0, len(arr)-1, x)

print("Answer =", ans)

